'use client';

import * as React from 'react';
import { CreditCard, Sparkles, Check, Loader2, ArrowRight } from 'lucide-react';
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
} from '@/components/ui/sheet';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { cn } from '@/lib/utils';
import { useToast } from '@/hooks/use-toast';

type PlanRenewalDialogProps = {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  planName: string;
  pricePerPeriod: number; // In euros
  billingCycle?: 'monthly' | 'quarterly' | 'annual';
  companyId: string;
  currentEndDate?: number; // Timestamp
  planStartDate: number; // Timestamp
  onCheckout: (args: {
    companyId: any;
    planName: string;
    totalAmount: number;
    periods: number;
    billingCycle?: string;
  }) => Promise<{ url: string | null }>;
};

const ANNUAL_DISCOUNTS: Record<number, number> = {
  1: 0,
  2: 0.04, // 4%
  3: 0.10, // 10%
};

const MONTHLY_DISCOUNTS: Record<number, number> = {
  1: 0,
  3: 0.05, // 5%
  6: 0.10, // 10%
  12: 0.20, // 20%
};

const QUARTERLY_DISCOUNTS: Record<number, number> = {
  1: 0,
  2: 0.05, // 5% (6 months)
  4: 0.15, // 15% (1 year)
};

function formatDate(timestamp: number): string {
  return new Date(timestamp).toLocaleDateString('es-ES', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
  });
}

function formatCurrency(amount: number): string {
  return new Intl.NumberFormat('es-ES', {
    style: 'currency',
    currency: 'EUR',
    minimumFractionDigits: 2,
  }).format(amount);
}

function calculateNewEndDate(
  planStartDate: number,
  currentEndDate: number | undefined,
  periods: number,
  billingCycle: 'monthly' | 'quarterly' | 'annual'
): Date {
  const baseDate = currentEndDate
    ? new Date(currentEndDate)
    : new Date(planStartDate);
  const newDate = new Date(baseDate);
  if (billingCycle === 'monthly') {
    newDate.setMonth(newDate.getMonth() + periods);
  } else if (billingCycle === 'quarterly') {
    newDate.setMonth(newDate.getMonth() + (periods * 3));
  } else {
    newDate.setFullYear(newDate.getFullYear() + periods);
  }
  return newDate;
}

export function PlanRenewalDialog({
  open,
  onOpenChange,
  planName,
  pricePerPeriod,
  billingCycle = 'annual',
  companyId,
  currentEndDate,
  planStartDate,
  onCheckout,
}: PlanRenewalDialogProps) {
  const { toast } = useToast();
  const [selectedPeriods, setSelectedPeriods] = React.useState(1);
  const [isLoading, setIsLoading] = React.useState(false);

  // Reset selected periods when billing cycle changes
  React.useEffect(() => {
    setSelectedPeriods(1);
  }, [billingCycle]);

  const isMonthly = billingCycle === 'monthly';
  const isQuarterly = billingCycle === 'quarterly';
  const discounts = isMonthly ? MONTHLY_DISCOUNTS : (isQuarterly ? QUARTERLY_DISCOUNTS : ANNUAL_DISCOUNTS);
  const discount = discounts[selectedPeriods] || 0;
  const subtotal = pricePerPeriod * selectedPeriods;
  const discountAmount = subtotal * discount;
  const total = subtotal - discountAmount;
  const newEndDate = calculateNewEndDate(planStartDate, currentEndDate, selectedPeriods, billingCycle);

  const handleCheckout = async () => {
    setIsLoading(true);
    try {
      const result = await onCheckout({
        companyId,
        planName,
        totalAmount: total,
        periods: selectedPeriods,
        billingCycle,
      });
      if (result?.url) {
        window.location.href = result.url;
      }
    } catch (error) {
      toast({
        variant: 'destructive',
        title: 'Error',
        description: 'No se pudo iniciar el proceso de pago. Inténtalo de nuevo.',
      });
      setIsLoading(false);
    }
  };

  const periodOptions = isMonthly ? [
    { periods: 1, label: '1 mes', tagline: 'Precio estándar' },
    { periods: 3, label: '3 meses', tagline: 'Ahorra un 5%' },
    { periods: 6, label: '6 meses', tagline: 'Ahorra un 10%' },
    { periods: 12, label: '12 meses', tagline: 'Ahorra un 20%' },
  ] : isQuarterly ? [
    { periods: 1, label: '1 trimestre', tagline: 'Precio estándar' },
    { periods: 2, label: '2 trimestres', tagline: 'Ahorra un 5%' },
    { periods: 4, label: '1 año', tagline: 'Ahorra un 15%' },
  ] : [
    { periods: 1, label: '1 año', tagline: 'Precio estándar' },
    { periods: 2, label: '2 años', tagline: 'Ahorra un 4%' },
    { periods: 3, label: '3 años', tagline: 'Ahorra un 10%' },
  ];

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent side="right" className="w-full sm:max-w-lg overflow-y-auto">
        <SheetHeader className="pb-4">
          <SheetTitle className="flex items-center gap-2 text-xl">
            <div className="flex items-center justify-center w-10 h-10 rounded-xl bg-primary/10">
              <CreditCard className="h-5 w-5 text-primary" />
            </div>
            Renovar Plan {planName}
          </SheetTitle>
          <SheetDescription>
            Selecciona la duración de tu renovación. Mayor duración, mayor ahorro.
          </SheetDescription>
        </SheetHeader>

        {/* Price per period */}
        <div className="mt-2 p-4 rounded-xl bg-muted/30 border">
          <div className="flex items-center justify-between">
            <span className="text-sm text-muted-foreground">Precio base</span>
            <span className="text-lg font-bold">{formatCurrency(pricePerPeriod)} <span className="text-sm font-normal text-muted-foreground">/ {isMonthly ? 'mes' : isQuarterly ? 'trimestre' : 'año'}</span></span>
          </div>
        </div>

        {/* Period selector */}
        <div className="mt-6 space-y-3">
          <label className="text-sm font-semibold text-foreground">Duración de la renovación</label>
          <div className={cn("grid gap-3", isMonthly ? "grid-cols-2" : "grid-cols-3")}>
            {periodOptions.map((option) => {
              const optDiscount = discounts[option.periods] || 0;
              const optTotal = pricePerPeriod * option.periods * (1 - optDiscount);
              const isSelected = selectedPeriods === option.periods;

              return (
                <button
                  key={option.periods}
                  onClick={() => setSelectedPeriods(option.periods)}
                  className={cn(
                    'relative flex flex-col items-center gap-1.5 p-4 rounded-xl border-2 transition-all duration-200 cursor-pointer',
                    isSelected
                      ? 'border-primary bg-primary/5 shadow-[0_0_0_1px_rgba(155,110,253,0.3)]'
                      : 'border-border bg-card hover:border-primary/30 hover:bg-muted/50'
                  )}
                >
                  {option.periods === (isMonthly ? 12 : isQuarterly ? 4 : 3) && (
                    <Badge variant="default" className="absolute -top-2.5 text-[10px] px-2 py-0 bg-gradient-to-r from-primary to-brand-pink border-0">
                      <Sparkles className="h-3 w-3 mr-1" />
                      Mejor precio
                    </Badge>
                  )}
                  <span className={cn(
                    'text-lg font-bold',
                    isSelected ? 'text-primary' : 'text-foreground'
                  )}>
                    {option.label}
                  </span>
                  <span className="text-base font-semibold tabular-nums">
                    {formatCurrency(optTotal)}
                  </span>
                  {optDiscount > 0 && (
                    <Badge variant="success" className="text-[10px] px-1.5 py-0">
                      -{Math.round(optDiscount * 100)}%
                    </Badge>
                  )}
                  <span className="text-[11px] text-muted-foreground">
                    {option.tagline}
                  </span>
                  {isSelected && (
                    <div className="absolute top-2 right-2">
                      <Check className="h-4 w-4 text-primary" />
                    </div>
                  )}
                </button>
              );
            })}
          </div>
        </div>

        {/* Price breakdown */}
        <div className="mt-6 p-4 rounded-xl bg-muted/30 border space-y-3">
          <div className="flex items-center justify-between text-sm">
            <span className="text-muted-foreground">Subtotal ({selectedPeriods} {selectedPeriods === 1 ? (isMonthly ? 'mes' : isQuarterly ? 'trimestre' : 'año') : (isMonthly ? 'meses' : isQuarterly ? 'trimestres' : 'años')})</span>
            <span className="tabular-nums">{formatCurrency(subtotal)}</span>
          </div>
          {discount > 0 && (
            <div className="flex items-center justify-between text-sm">
              <span className="text-green-500">Descuento ({Math.round(discount * 100)}%)</span>
              <span className="text-green-500 tabular-nums">-{formatCurrency(discountAmount)}</span>
            </div>
          )}
          <div className="border-t pt-3 flex items-center justify-between">
            <span className="text-base font-bold">Total</span>
            <span className="text-2xl font-black tabular-nums">{formatCurrency(total)}</span>
          </div>
        </div>

        {/* New end date info */}
        <div className="mt-4 p-3 rounded-xl bg-brand-blue/5 border border-brand-blue/20">
          <div className="flex items-center gap-2 text-sm">
            <span className="text-brand-blue font-medium">Nueva fecha de fin:</span>
            <span className="font-bold">{formatDate(newEndDate.getTime())}</span>
          </div>
        </div>

        {/* Checkout button */}
        <div className="mt-6">
          <Button
            className="w-full h-14 text-base font-bold bg-primary hover:bg-primary/90 text-primary-foreground shadow-lg shadow-primary/20 transition-all"
            onClick={handleCheckout}
            disabled={isLoading}
          >
            {isLoading ? (
              <>
                <Loader2 className="mr-2 h-5 w-5 animate-spin" />
                Redirigiendo a Stripe...
              </>
            ) : (
              <>
                Pagar {formatCurrency(total)}
                <ArrowRight className="ml-2 h-5 w-5" />
              </>
            )}
          </Button>
          <p className="text-center text-[11px] text-muted-foreground mt-3">
            Serás redirigido a Stripe para completar el pago de forma segura.
          </p>
        </div>
      </SheetContent>
    </Sheet>
  );
}
